   113|async function ghFetch(path) {
   114|  const res = await fetch(`${GITHUB_API}${path}`, {
   115|    headers: {
   116|      Authorization: `Bearer ${GITHUB_TOKEN}`,
   117|      Accept: 'application/vnd.github+json',
