   183|      proof.nodes.github.ok = !!proof.githubCommit;
   184|      proof.nodes.github.detail = `${REPO_SLUG}@${GITHUB_BRANCH} head ${short(proof.githubCommit)}`;
   185|      console.log(`[watchdog] github commit: ${short(proof.githubCommit)}`);
   186|    } catch (err) {
   187|      fail('github', 'network egress + GITHUB_TOKEN', `GitHub API request failed: ${err.message}`);
   188|    }
   189|  } else {
   190|    proof.nodes.github.detail = !GITHUB_TOKEN
   191|      ? 'GITHUB_TOKEN missing from process env'
   192|      : 'GITHUB_REPO_URL missing from process env';
   193|  }
   194|
   195|  // ── Node 4: Render deploy ──────────────────────────────────────────────
