   210|      let live = null;
   211|      do {
   212|        const res = await renderFetch(`/services/${RENDER_SERVICE_ID}/deploys?limit=1`);
   213|        if (!res.ok) {
   214|          fail('render', 'RENDER_API_KEY with read access on RENDER_SERVICE_ID',
   215|            `Render deploys API returned HTTP ${res.status}.`);
   216|        }
   217|        const list = await res.json();
   218|        const d = Array.isArray(list) ? list[0]?.deploy : null;
   219|        if (d) {
   220|          if (d.status === 'live') { live = d; break; }
   221|          if (['build_failed', 'update_failed', 'canceled', 'deactivated'].includes(d.status)) {
   222|            fail('render', 'a successful Render build',
   223|              `Latest Render deploy ended with status "${d.status}" (commit ${short(d.commit?.id)}).`);
   224|          }
   225|          if (!DO_DEPLOY) { live = d; break; }
   226|        }
   227|        await new Promise((r) => setTimeout(r, 10_000));
   228|      } while (Date.now() < deadline);
   229|
   230|      if (!live && DO_DEPLOY) {
   231|        fail('render', 'a faster/successful Render build', `Render deploy did not reach "live" within ${MAX_WAIT_SECONDS}s.`);
   232|      }
