   237|    } catch (err) {
   238|      fail('render', 'network egress + RENDER_API_KEY', `Render API request failed: ${err.message}`);
   239|    }
   240|  } else {
   241|    proof.nodes.render.detail = !RENDER_API_KEY
   242|      ? 'RENDER_API_KEY missing from process env'
   243|      : 'RENDER_SERVICE_ID missing from process env';
   244|  }
   245|
   246|  // ── Node 5: Production /version ────────────────────────────────────────
   247|  if (PRODUCTION_BASE_URL) {
   248|    try {
