   250|      if (!res.ok) {
   251|        fail('production', 'reachable production /version endpoint',
   252|          `${PRODUCTION_BASE_URL}/version returned HTTP ${res.status}.`);
   253|      }
   254|      const data = await res.json();
   255|      proof.productionCommit = data?.commit || data?.commitShort || '';
